public class Student {
  String name;
  int age;

  Student(String name, int age) {
    this.name = name;
    this.age = age;
  }

  void displayInfo() {
    System.out.println("Ad: " + name + ", Yaş: " + age);
  }

  public static void main(String[] args) {
    Student student = new Student("Aysel", 20);
    student.displayInfo();
  }
}
// Çıxış: Ad: Aysel, Yaş: 20

public class Person {
  private String name;
  private int age;

  public Person(String name, int age) {
    this.name = name;
    this.age = age;
  }

  public String getName() {
    return name;
  }

  public void setName(String name) {
    this.name = name;
  }

  public int getAge() {
    return age;
  }

  public void setAge(int age) {
    if (age > 0) {
      this.age = age;
    }
  }

  public static void main(String[] args) {
    Person person = new Person("Murad", 25);
    System.out.println("Ad: " + person.getName() + ", Yaş: " + person.getAge());
    person.setAge(30);
    System.out.println("Yeni yaş: " + person.getAge());
  }
}
// Çıxış:
// Ad: Murad, Yaş: 25
// Yeni yaş: 30

